const data = $json;

if (data.status === 'running') {
  return [{ json: { auctions: [], still_running: true, qualifying_count: 0 } }];
}

const all = data.data || [];

const qualifying = all.filter(function(a) {
  const dept = (a.location_department || '').toUpperCase();
  const isLima = dept.includes('LIMA') || dept.includes('CALLAO');
  const okPrice = a.price_usd && a.price_usd <= 90000;
  return isLima && okPrice;
});

qualifying.sort(function(a, b) { return (a.price_usd || 0) - (b.price_usd || 0); });

const stats = {
  pages_scraped: data.pagesScraped || 0,
  duration_ms: data.durationMs || 0,
  total_found: all.length,
  qualifying_count: qualifying.length
};

return [{ json: { auctions: qualifying, stats: stats, still_running: false } }];

const auctions = $json.auctions;
const stats = $json.stats || {};
const BOT_TOKEN = '8481244553:AAG1p0ExiDfLP1khxYzzRp-OLj5ik-MuH4s';
const CHAT_ID = '7727513100';
const API_URL = 'https://api.telegram.org/bot' + BOT_TOKEN + '/sendMessage';

function esc(s) {
  return String(s).replace(/[_*[\]()~`>#+=|{}.!\\-]/g, '\\$&');
}

const TIER_EMOJI = { super_ganga: String.fromCodePoint(0x1F534), muy_bueno: String.fromCodePoint(0x1F7E0), bueno: String.fromCodePoint(0x1F7E1), aceptable: String.fromCodePoint(0x1F7E2) };
const TYPE_EMOJI = { casa: String.fromCodePoint(0x1F3E0), departamento: String.fromCodePoint(0x1F3E2), terreno: String.fromCodePoint(0x1F33F), local: String.fromCodePoint(0x1F6EA), otro: String.fromCodePoint(0x1F3D7) };
const LINE = String.fromCodePoint(0x2501).repeat(22);

async function sendMsg(text, disablePreview) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: API_URL,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: CHAT_ID,
        text: text,
        parse_mode: 'MarkdownV2',
        disable_web_page_preview: disablePreview !== false
      })
    });
    return res;
  } catch(e) {
    // Fallback plain
    const plain = text.replace(/[*_`\[\]()~>#+=|{}.!\\]/g, '');
    return await this.helpers.httpRequest({
      method: 'POST',
      url: API_URL,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ chat_id: CHAT_ID, text: plain, disable_web_page_preview: true })
    });
  }
}

const results = [];

if (auctions.length > 8) {
  const tierCount = { super_ganga: 0, muy_bueno: 0, bueno: 0, aceptable: 0 };
  auctions.forEach(function(a) { if (a.price_usd_tier && tierCount[a.price_usd_tier] !== undefined) tierCount[a.price_usd_tier]++; });

  const date = new Date().toLocaleDateString('es-PE', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'America/Lima' });
  const top3 = auctions.slice(0, 3);

  const lines = [
    String.fromCodePoint(0x1F4CA) + ' *RESUMEN DIARIO REMAJU*',
    LINE,
    esc(date),
    '',
    esc(auctions.length + ' nuevas propiedades < $90k USD'),
    '',
    tierCount.super_ganga ? esc(TIER_EMOJI.super_ganga + ' Super Ganga (< $40k): ' + tierCount.super_ganga) : null,
    tierCount.muy_bueno   ? esc(TIER_EMOJI.muy_bueno   + ' Muy Bueno  ($40-60k): ' + tierCount.muy_bueno)   : null,
    tierCount.bueno       ? esc(TIER_EMOJI.bueno       + ' Bueno      ($60-75k): ' + tierCount.bueno)       : null,
    tierCount.aceptable   ? esc(TIER_EMOJI.aceptable   + ' Aceptable  ($75-90k): ' + tierCount.aceptable)   : null,
    '',
    '*' + String.fromCodePoint(0x1F3C6) + ' Top 3 m\u00e1s econ\u00f3micas:*',
    top3.map(function(a, i) { return esc((i+1) + '. $' + Math.round(a.price_usd).toLocaleString('es-PE') + ' \u2014 ' + (a.location_district || 'Lima')); }).join('\n'),
    '',
    stats.pages_scraped ? esc('_P\u00e1ginas: ' + stats.pages_scraped + ' | ' + Math.round((stats.duration_ms || 0) / 60000) + ' min_') : null
  ].filter(function(l) { return l !== null; }).join('\n');

  const r = await sendMsg.call(this, lines, true);
  results.push({ json: { sent: 1, type: 'digest', response: r } });

} else {
  for (let i = 0; i < auctions.length; i++) {
    const a = auctions[i];
    const tier = a.price_usd_tier || 'aceptable';
    const emoji = TIER_EMOJI[tier] || TIER_EMOJI.aceptable;
    const typeEmoji = TYPE_EMOJI[a.property_type] || TYPE_EMOJI.otro;
    const tier_uc = tier.replace('_', ' ').toUpperCase();
    const priceUsd = Math.round(a.price_usd);
    const pricePen = a.currency_original === 'PEN' ? Math.round(a.price_original) : null;
    const tc = a.exchange_rate ? parseFloat(a.exchange_rate).toFixed(2) : '3.72';
    const district = a.location_district || a.location_department || 'Lima';
    const tipo = (a.property_type || 'inmueble').charAt(0).toUpperCase() + (a.property_type || 'inmueble').slice(1);

    let fase = '';
    if (a.auction_phase) {
      if (a.auction_phase.includes('SEGUNDA')) fase = '2da Conv \u219315%';
      else if (a.auction_phase.includes('TERCERA')) fase = '3ra Conv \u219330%';
      else fase = '1ra Conv';
    }

    let days = null;
    if (a.auction_date) {
      days = Math.ceil((new Date(a.auction_date) - new Date()) / 86400000);
    }

    const priceStr = (pricePen ? 'S/ ' + pricePen.toLocaleString('es-PE') + '  \u2248  ' : '') + '$' + priceUsd.toLocaleString('es-PE') + ' USD';

    const lines = [
      emoji + ' *' + tier_uc + ' \u2014 REMATE LIMA*',
      LINE,
      esc(String.fromCodePoint(0x1F4B0) + '  ' + priceStr),
      esc(String.fromCodePoint(0x1F4B1) + '  TC: S/ ' + tc + ' x USD'),
      esc(String.fromCodePoint(0x1F4CD) + '  ' + district + ', Lima'),
      esc(typeEmoji + '  ' + tipo + (fase ? ' \u00b7 ' + fase : '')),
      a.area_m2 ? esc(String.fromCodePoint(0x1F4D0) + '  ' + a.area_m2 + ' m\u00b2') : null,
      a.auction_date ? esc(String.fromCodePoint(0x1F4C5) + '  Remate: ' + a.auction_date + (days !== null ? ' (' + days + ' d\u00edas)' : '')) : null,
      esc(String.fromCodePoint(0x1F4CB) + '  ' + (a.title || 'Remate REMAJU')),
      '',
      '[' + String.fromCodePoint(0x1F517) + ' Ver en REMAJU](https://remaju.pj.gob.pe/remaju/pages/publico/remateExterno.xhtml)'
    ].filter(function(l) { return l !== null; }).join('\n');

    const r = await sendMsg.call(this, lines, false);
    results.push({ json: { sent: 1, type: 'individual', index: i, response: r } });

    // Rate limit: small delay between messages
    await new Promise(function(resolve) { setTimeout(resolve, 500); });
  }
}

return results.length ? results : [{ json: { sent: 0 } }];
